@startuml
skinparam classAttributeIconSize 0
hide circle

class "AbstractFactoryPatternDemo" as AbstractFactoryPatternDemo {
    void main()
}

interface Shape <<I>> {
    void draw()
}

abstract class Circle implements Shape {
    void draw()
}

abstract class Rectangle implements Shape {
    void draw()
}

abstract class Square implements Shape {
    void draw()
}


package shape{
Shape <|-- Circle : implement 
Rectangle --|> Shape :implement  
Square -up-|> Shape: implement 

Circle --> Shape
Rectangle -> Shape
Square ---> Shape 


'note right of package::shape\nthis is note\nto show you can add notes to packages.\nend note



}




